import{_ as a,o as i,c as o,a2 as e}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"如何买入期权","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/options/how-to-buy-options.md","filePath":"zh-CN/derivatives/options/how-to-buy-options.md"}'),r={name:"derivatives/options/how-to-buy-options.md"};function l(n,t,s,h,d,p){return i(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="如何买入期权" tabindex="-1">如何买入期权 <a class="header-anchor" href="#如何买入期权" aria-label="Permalink to &quot;如何买入期权&quot;">​</a></h1><p>本指南说明如何在长桥 App 上找到目标期权合约并完成买入下单，适用于已开通期权交易权限的用户。</p><blockquote><p>如果尚未开通期权权限，请先参阅<a href="/wiki/derivatives/options/enable-options">开通期权交易</a>。</p></blockquote><hr><h2 id="第一步-进入标的股票的期权链" tabindex="-1">第一步：进入标的股票的期权链 <a class="header-anchor" href="#第一步-进入标的股票的期权链" aria-label="Permalink to &quot;第一步：进入标的股票的期权链&quot;">​</a></h2><ol><li>在搜索栏输入标的股票名称或代码（如 AAPL、TSLA）</li><li>进入该股票的详情页</li><li>点击顶部 Tab 栏中的「<strong>期权链</strong>」</li></ol><p>期权链页面会显示该股票所有可交易的期权合约，默认展示近期到期日。</p><hr><h2 id="第二步-选择到期日" tabindex="-1">第二步：选择到期日 <a class="header-anchor" href="#第二步-选择到期日" aria-label="Permalink to &quot;第二步：选择到期日&quot;">​</a></h2><p>在页面顶部横向滚动到期日列表，选择目标到期日。</p><ul><li><strong>「W」标记</strong>：周期权，每周五到期，时间价值衰减较快</li><li><strong>无标记</strong>：月期权，通常为每月第三个周五到期，流动性较好</li></ul><p>如果对到期日没有特定需求，建议选择距今 <strong>2–4 周</strong>的合约，流动性和时间价值相对均衡。</p><hr><h2 id="第三步-选择方向和行权价" tabindex="-1">第三步：选择方向和行权价 <a class="header-anchor" href="#第三步-选择方向和行权价" aria-label="Permalink to &quot;第三步：选择方向和行权价&quot;">​</a></h2><p><strong>确定方向：</strong></p><table tabindex="0"><thead><tr><th>预期</th><th>选择</th></tr></thead><tbody><tr><td>看涨，预期股价上涨</td><td>Call（看涨期权）</td></tr><tr><td>看跌，预期股价下跌</td><td>Put（看跌期权）</td></tr></tbody></table><p><strong>选择行权价：</strong></p><p>合约列表以当前股价为中轴排列，蓝色背景的合约为**价内（ITM）**期权：</p><ul><li><strong>价内期权</strong>（行权价接近或优于当前股价）：权利金较高，内在价值高，Delta 较大</li><li><strong>价外期权</strong>（行权价远离当前股价）：权利金较低，需要股价大幅移动才能盈利，风险较高</li></ul><p>点击目标合约行，进入合约详情页。</p><hr><h2 id="第四步-下单" tabindex="-1">第四步：下单 <a class="header-anchor" href="#第四步-下单" aria-label="Permalink to &quot;第四步：下单&quot;">​</a></h2><p>在合约详情页：</p><ol><li>点击右下角「<strong>买入</strong>」</li><li>确认合约信息：标的、方向（Call/Put）、行权价、到期日</li><li>填写委托张数（1 张 = 100 股）</li><li>选择委托类型： <ul><li><strong>限价</strong>：指定最高愿意支付的价格，价格合适时成交</li><li><strong>市价</strong>：以当前市场价即时成交（注意买卖价差）</li></ul></li><li>点击「提交委托」</li></ol><hr><h2 id="第五步-确认持仓" tabindex="-1">第五步：确认持仓 <a class="header-anchor" href="#第五步-确认持仓" aria-label="Permalink to &quot;第五步：确认持仓&quot;">​</a></h2><p>下单成功后，进入「资产」→「持仓」，确认期权仓位已出现。</p><p>持仓显示为<strong>多头（正数数量）</strong>，说明你持有该期权的买方权利。权利金已从账户余额扣除。</p><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/derivatives/options/options-buyer">期权买方</a> — 看涨/看跌期权盈亏结构与行权逻辑说明</li><li><a href="/wiki/derivatives/options/options-chain">期权链</a> — 期权链页面各字段含义说明</li><li><a href="/wiki/derivatives/options/enable-options">开通期权交易</a> — 权限级别与申请流程</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/derivatives/options/options-buyer">期权买方</a></li><li><a href="/wiki/derivatives/options/options-seller">期权卖方</a></li></ul>',33)])])}const b=a(r,[["render",l]]);export{c as __pageData,b as default};
